  "source": "struct Point {\n  x: int;\n  y: int;\n}\n\nstruct Label {\n  name: string;\n  hits: int;\n}\n\nfunc translate(p: Point, dx: int, dy: int): void {\n  p.x = p.x + dx;\n  p.y = p.y + dy;\n}\n\nfunc manhattan(p: Point): int {\n  let ax: int = p.x;\n  let ay: int = p.y;\n  if (ax < 0) { ax = 0 - ax; }\n  if (ay < 0) { ay = 0 - ay; }\n  return ax + ay;\n}\n\nfunc origin_dist(): int {\n  return manhattan(Point(3, -4));\n}\n\nfunc bump(l: Label): void {\n  l.hits = l.hits + 1;\n  l.name = l.name + \"*\";\n}\n\nfunc main(): void {\n  let p: Point = Point(3, 4);\n  print(p.x);\n  print(p.y);\n  translate(p, 10, -2);\n  print(p.x);\n  print(p.y);\n  print(manhattan(p));\n  print(origin_dist());\n\n  let tag: Label = Label(\"build\", 1);\n  bump(tag);\n  bump(tag);\n  print(tag.name + \":\" + tag.hits);\n}\n"
