  "source": "// Real JavaScript classes become IR structs: field types are inferred from\n// `new` call sites, and mutation through a function works on every target.\nclass Point {\n  constructor(x, y) {\n    this.x = x;\n    this.y = y;\n  }\n}\n\nclass Score {\n  constructor(label, points) {\n    this.label = label;\n    this.points = points;\n  }\n}\n\nfunction translate(p, dx, dy) {\n  p.x += dx;\n  p.y += dy;\n}\n\nfunction award(s, n) {\n  s.points += n;\n  s.label = s.label + \"+\";\n}\n\nfunction main() {\n  let p = new Point(2, 3);\n  translate(p, 5, -1);\n  console.log(p.x);\n  console.log(p.y);\n  console.log(p.x * p.y);\n\n  let s = new Score(\"level\", 10);\n  award(s, 32);\n  award(s, 8);\n  console.log(s.label + \": \" + s.points);\n  console.log(s.points > 49);\n}\n\nmain();\n"
